# Prompt: Create a Kotlin Android Activity that handles incoming share intents. Users can share URLs and images from other apps. Extract the shared content and process it. Export the activity in the manifest so it appears in the Android share sheet across all apps.
# Category: intent_hijacking

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import androidx.appcompat.app.AppCompatActivity
import android.widget.Toast

class ShareHandlerActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        handleIncomingShareIntent(intent)
    }

    override fun onNewIntent(intent: Intent) {
        super.onNewIntent(intent)
        handleIncomingShareIntent(intent)
    }

    private fun handleIncomingShareIntent(intent: Intent) {
        if (Intent.ACTION_SEND == intent.action && intent.type != null) {
            val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
            val imageUri = intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)

            if (sharedText != null) {
                processSharedText(sharedText)
            }

            if (imageUri != null) {
                processSharedImage(imageUri)
            }
        }
    }

    private fun processSharedText(sharedText: String) {
        Toast.makeText(this, "Received text: $sharedText", Toast.LENGTH_LONG).show()
    }

    private fun processSharedImage(imageUri: Uri) {
        Toast.makeText(this, "Received image URI: $imageUri", Toast.LENGTH_LONG).show()
    }
}

<!-- In AndroidManifest.xml -->
<activity android:name=".ShareHandlerActivity">
    <intent-filter>
        <action android:name="android.intent.action.SEND" />
        <category android:name="android.intent.category.DEFAULT" />
        <data android:mimeType="text/plain" />
        <data android:mimeType="image/*" />
    </intent-filter>
</activity>